// ---- Scene instances ----
struct TmScene {
    char name[32] = "";
    int mapW = 1, mapH = 1;        // grid dimensions in tiles
    float zoom = 1.0f;             // editor canvas zoom level
    int pixelScale = 1;            // export pixel scale (1=normal, 2=2x zoom)
    // Per-scene tilemap data
    std::vector<uint16_t> tileIndices;  // saved tile grid
    std::vector<TmObject> objects;      // saved objects
    // Scene-level blueprint attachment
    int blueprintIdx = -1;
    struct { int paramIdx; int value; } instanceParams[8] = {};
    int instanceParamCount = 0;
};
static std::vector<TmScene> sTmScenes;
static int sTmSelectedScene = 0;     // active scene index
static float sTmScenePanelW = 180.0f; // scene panel width

// Save current tilemap state into the given scene
static void SaveSceneState(TmScene& sc)
{
    sc.mapW = sTilemapData.floor.width;
    sc.mapH = sTilemapData.floor.height;
    sc.zoom = sTmMapZoom;
    sc.tileIndices = sTilemapData.floor.tileIndices;
    sc.objects = sTmObjects;
}

// Load a scene's tilemap state into the active tilemap
static void LoadSceneState(const TmScene& sc)
{
    sTilemapData.floor.width  = sc.mapW;
    sTilemapData.floor.height = sc.mapH;
    sTmMapZoom = sc.zoom;
    if (!sc.tileIndices.empty())
        sTilemapData.floor.tileIndices = sc.tileIndices;
    else
        sTilemapData.floor.tileIndices.assign(sc.mapW * sc.mapH, 0);
    sTmObjects = sc.objects;
    sTmSelectedObj = -1;
    sTmDragObj = -1;
    sTmStampObj = -1;
}

// ---- Visual Script Node System ----
enum class VsNodeType : int {
    // Events (triggers — green, no input exec pin)
    OnKeyPressed = 0, OnKeyReleased, OnKeyHeld,
    OnCollision,
    OnStart,
    // Logic (blue)
    Branch,         // if/else
    CompareVar,     // variable comparison
    // Actions (orange, has input exec pin)
    MovePlayer,
    LookDirection,
    ChangeScene,
    SetVariable,
    AddVariable,
    PlaySound,
    Wait,
    Jump,           // player jump
    Walk,           // set walk speed
    Sprint,         // set sprint speed
    OrbitCamera,    // rotate orbit camera
    PlayAnim,       // play animation on player sprite
    SetGravity,     // set gravity value
    SetMaxFall,     // set max fall speed
    DestroyObject,  // remove sprite/object from scene
    AutoOrbit,      // auto-orbit camera when strafing
    DampenJump,     // reduce upward velocity while A released (variable jump height)
    Integer,        // constant integer output
    Key,            // constant key output (A/B/L/R/etc)
    Direction,      // constant direction output (Left/Right/Up/Down)
    Animation,      // constant animation index output
    Float,          // constant float output
    OnUpdate,       // fires every frame
    Group,          // subgraph containing other nodes
    Object,         // constant object/sprite index output (dropdown)
    CustomCode,     // user-written C code
    IsMoving,       // condition gate: passes exec only if player is moving
    IsOnGround,     // condition gate: passes exec only if player is on ground
    IsJumping,      // condition gate: passes exec only if player is airborne + rising
    IsFalling,      // condition gate: passes exec only if player is airborne + falling
    CheckFlag,      // condition: branch on flag set/clear (2 exec outs)
    SetFlag,        // set a flag bit (0-31)
    ToggleFlag,     // toggle a flag bit
    FreezePlayer,   // disable player input
    UnfreezePlayer, // re-enable player input
    SetCameraHeight,// set camera Y height
    SetHorizon,     // set horizon scanline
    Teleport,       // teleport player to x,y,z
    SetVisible,     // show/hide a sprite
    SetPosition,    // set sprite position
    StopAnim,       // stop animation playback
    SetAnimSpeed,   // set animation playback speed
    SetVelocityY,   // set vertical velocity directly
    StopSound,      // stop all sound
    AddMath,        // A + B
    SubtractMath,   // A - B
    MultiplyMath,   // A * B
    NegateMath,     // -A
    RandomInt,      // random int in [Min, Max]
    GetFlag,        // read flag value (data node)
    // Math/logic data nodes
    AbsMath,        // |A|
    MinMath,        // min(A, B)
    MaxMath,        // max(A, B)
    ModuloMath,     // A % B
    ClampMath,      // clamp(Val, Min, Max)
    SignMath,       // sign(A): -1, 0, or 1
    CompareInt,     // A op B -> 0 or 1
    AndLogic,       // A && B
    OrLogic,        // A || B
    NotLogic,       // !A
    GetVariable,    // read variable slot
    GetPlayerX,     // read player X position
    GetPlayerZ,     // read player Z position
    // Actions
    OnTimer,        // event: fires every N frames
    SetScale,       // set sprite scale
    ScreenShake,    // camera shake for N frames
    FadeOut,        // fade screen to black
    FadeIn,         // fade screen from black
    MoveToward,     // move sprite toward position
    LookAt,         // face sprite toward object
    SetSpriteAnim,  // play animation on specific sprite
    SpawnEffect,    // visual effect at position
    // Flow control
    DoOnce,         // only fires downstream once per play session
    FlipFlop,       // alternates between two exec outputs each trigger
    Gate,           // open/close gate that blocks or passes exec
    ForLoop,        // repeat downstream N times
    Sequence,       // fire exec outputs in order (1, then 2)
    // More data nodes
    Select,         // pick A or B based on condition
    Lerp,           // linear interpolation A->B by T
    Distance,       // distance between two sprites
    GetSpriteX,     // read any sprite's X
    GetSpriteZ,     // read any sprite's Z
    IsKeyDown,      // outputs 1/0 for whether a key is held
    SinWave,        // oscillating value over time
    GetTime,        // frame counter as data
    // Game systems
    SetHP,          // set health points
    GetHP,          // read health points
    DamageHP,       // subtract from HP
    AddScore,       // add to score counter
    GetScore,       // read score
    Respawn,        // reset player to start position
    SaveData,       // save flags to SRAM
    LoadData,       // load flags from SRAM
    // More visual/object
    FlipSprite,     // flip sprite horizontally
    SetDrawDist,    // change draw distance at runtime
    EnableCollision,// enable/disable collision on object
    // More conditions
    IsFlagSet,      // gate: passes if flag is set
    IsHPZero,       // gate: passes if sprite HP == 0
    IsNear,         // gate: passes if two sprites within radius
    // Timers/counters
    Countdown,      // decrement counter, fire when reaches 0
    ResetTimer,     // reset a timer node's counter
    Increment,      // increment variable slot by 1
    Decrement,      // decrement variable slot by 1
    // Camera
    SetFOV,         // set camera FOV
    ShakeStop,      // stop screen shake
    LockCamera,     // lock camera angle
    UnlockCamera,   // unlock camera angle
    SetCamSpeed,    // set camera follow speed
    // Physics
    ApplyForce,     // add to velocity
    Bounce,         // reverse Y velocity with damping
    SetFriction,    // set ground friction
    // Object spawning
    CloneSprite,    // duplicate a sprite at runtime
    HideAll,        // hide all sprites
    ShowAll,        // show all sprites
    // Data
    Divide,         // A / B
    Power,          // A^B (integer)
    Remap,          // remap value from one range to another
    Average,        // (A + B) / 2
    GetHP2,         // alias: get HP as condition (>0 = alive)
    PingPong,       // bouncing value between min and max
    // Batch 5: Advanced gameplay
    Print,          // debug print integer to mGBA log
    SetColor,       // change sprite palette color
    SwapSprite,     // swap sprite asset at runtime
    GetAngle,       // angle between two sprites (brads)
    GetPlayerY,     // read player Y position (height)
    GetSpriteY,     // read any sprite's Y position
    SetSpriteY,     // set sprite Y position
    WaitUntil,      // block exec until condition is true
    RepeatWhile,    // keep firing while condition is true
    StopAll,        // stop all running scripts
    SetLayer,       // set sprite draw priority layer
    GetLayer,       // read sprite draw priority
    SetAlpha,       // set sprite alpha/blend level
    Flash,          // flash sprite white for N frames
    Delay,          // delay downstream exec by N frames (non-blocking)
    GetVelocityY,   // read player vertical velocity
    SetSpriteScale, // set specific sprite's scale
    RotateSprite,   // rotate sprite by angle
    GetRotation,    // get sprite rotation angle
    SetHP2,         // set HP with clamping to max
    HealHP,         // add HP (clamped to max)
    GetMaxHP,       // read max HP value
    SetMaxHP,       // set max HP for sprite
    IsAlive,        // gate: passes if sprite HP > 0
    // Batch 6: World & AI
    SetBGColor,     // set background/clear color
    GetDeltaTime,   // outputs frame delta (always 1 at 60fps)
    MapValue,       // map value from [inMin,inMax] to [outMin,outMax]
    Wrap,           // wrap value within [min, max] range
    SmoothStep,     // smoothstep interpolation
    EaseIn,         // ease-in (quadratic)
    EaseOut,        // ease-out (quadratic)
    DistToPlayer,   // distance from sprite to player
    FacePlayer,     // make sprite face toward player
    MoveForward,    // move sprite in its facing direction
    Patrol,         // move sprite between two points
    ChasePlayer,    // move sprite toward player
    FleePlayer,     // move sprite away from player
    SetAI,          // set AI behavior mode for sprite
    GetAI,          // get current AI behavior mode
    OnDeath,        // event: fires when sprite HP reaches 0
    OnHit,          // event: fires when sprite takes damage
    EmitParticle,   // spawn particle at position
    SetTint,        // set sprite color tint
    Shake,          // shake a specific sprite
    SetText,        // set HUD text slot
    ShowHUD,        // show HUD element
    HideHUD,        // hide HUD element
    GetRandom,      // random float 0.0-1.0 (as 0-256 fixed)
    ArrayGet,       // read from variable array slot
    ArraySet,       // write to variable array slot
    // Batch 7: Text / Inventory / Dialogue / State Machine
    // Text rendering
    DrawNumber,     // draw integer at screen X,Y
    DrawTextID,     // draw text string by ID at screen X,Y
    ClearText,      // clear all rendered text
    SetTextColor,   // set text color for next draw
    // Inventory
    AddItem,        // add item to inventory slot
    RemoveItem,     // remove item from inventory slot
    HasItem,        // gate: passes if item count > 0
    GetItemCount,   // read item quantity
    SetItemCount,   // set item quantity directly
    UseItem,        // consume one of an item (decrement)
    // Dialogue
    ShowDialogue,   // show dialogue box with text ID
    HideDialogue,   // close dialogue box
    NextLine,       // advance to next dialogue line
    IsDialogueOpen, // gate: passes if dialogue box is open
    SetSpeaker,     // set speaker portrait/name index
    DialogueChoice, // present 2 choices, branch on selection
    // State Machine
    SetState,       // set sprite state machine state
    GetState,       // read sprite current state
    OnStateEnter,   // event: fires when entering state
    OnStateExit,    // event: fires when exiting state
    IsInState,      // gate: passes if sprite in given state
    TransitionState,// change state after optional delay
    PrevState,      // read sprite's previous state
    StateTimer,     // frames spent in current state
    // Batch 8: Collision / Spawning / UI / Scene / Input
    // Collision
    OnTriggerEnter, // event: fires when sprite enters trigger zone
    OnTriggerExit,  // event: fires when sprite exits trigger zone
    SetCollisionSize,// change sprite collision radius at runtime
    IgnoreCollision,// disable collision between two specific sprites
    IsColliding,    // gate: passes if two sprites are currently overlapping
    // Spawning
    SpawnAt,        // spawn new sprite from asset at position
    DestroyAfter,   // auto-destroy sprite after N frames
    SpawnProjectile,// spawn + move in a direction at speed
    SetLifetime,    // set remaining lifetime for a sprite
    GetLifetime,    // read remaining lifetime
    // UI
    DrawBar,        // draw a horizontal bar (HP bar, progress, etc.)
    DrawSpriteIcon, // draw a sprite icon on HUD at screen pos
    ShowTimer,      // display countdown timer on screen
    HideTimer,      // hide countdown timer
    SetBarColor,    // set bar fill color
    SetBarMax,      // set bar maximum value
    // Scene/Level
    ReloadScene,    // restart current scene
    GetScene,       // read current scene index
    SetCheckpoint,  // save checkpoint position
    LoadCheckpoint, // respawn at checkpoint
    // Input
    GetInputAxis,   // returns -1/0/1 for dpad axis (data node)
    OnAnyKey,       // event: fires on any button press
    GetLastKey,     // read last key pressed (data node)
    OnCollision2D,  // event: fires when player collides with tilemap object (Mode 0)
    IsTrue,         // gate: passes exec if data input is non-zero
    CursorUp,       // move element cursor to previous stop (wraps)
    CursorDown,     // move element cursor to next stop (wraps)
    FollowLink,     // navigate to linked element at current cursor stop
    GetCursorStop,  // data: returns current cursor stop index
    BlueprintRef,   // data: constant blueprint definition index (dropdown)
    FollowPlayer,   // move sprite toward player, stop at distance
    IsNear2D,       // gate: passes if player is adjacent to this blueprint's tilemap object
    IsFollowMoving, // gate: passes if follow object is currently moving
    SetFollowFacing,// set follow object's facing direction from follow state
    SoundInstance,  // data node: select a sound instance by dropdown
    PlayHudAnim,    // play a HUD animation layer
    StopHudAnim,    // stop a HUD animation layer
    SetHudAnimSpeed, // set HUD animation layer speed
    OnRise,         // gate: passes exec only on frame condition becomes true (rising edge)
    ResetScene,     // action: reload the current scene (respawn)
    COUNT
};

struct VsNodeTypeDef {
    const char* name;
    ImU32 color;        // header color (ABGR)
    int inExec;         // number of exec input pins (0 for events)
    int outExec;        // number of exec output pins
    int inData;         // number of data input pins
    int outData;        // number of data output pins
    const char* inDataNames[4];
    const char* outDataNames[4];
    const char* outExecNames[4];
};

