struct VsNode {
    int id = 0;
    VsNodeType type = VsNodeType::OnStart;
    float x = 0, y = 0;          // canvas position
    // Per-node param values (interpreted based on type)
    int paramInt[4] = {};         // e.g. key index, var slot, pixels, scene index
    bool selected = false;        // multi-select flag
    // Group support
    int groupId = 0;              // 0 = top-level; >0 = inside group with this node id
    char groupLabel[32] = {};     // label for Group-type nodes
    int grpInExec = 0, grpOutExec = 0;   // dynamic pin counts for Group nodes
    int grpInData = 0, grpOutData = 0;
    char customCode[512] = {};            // GBA runtime code override (legacy, maps to codeRtMode4)
    char codeScene[512] = {};             // Mode 4 editor code override
    char codeTilemap[512] = {};           // Mode 0 editor code override
    char codeRtMode4[512] = {};           // Mode 4 runtime C implementation
    char codeRtMode0[512] = {};           // Mode 0 runtime C implementation
    char funcName[64] = {};               // custom function name (empty = use default afn_ name)
    char ccPinNames[8][16] = {};          // custom data-in pin labels for CustomCode nodes
    char ccPinCode[8][128] = {};          // per-pin code snippets for CustomCode nodes
};

// Pin address: which node, which pin type, which pin index
struct VsPin {
    int nodeId = -1;
    int pinType = 0;              // 0=execOut, 1=execIn, 2=dataOut, 3=dataIn
    int pinIdx = 0;
};

struct VsLink {
    VsPin from, to;
};

// Annotation boxes (drawn behind nodes)
struct VsAnnotation {
    float x, y, w, h;            // canvas-space position and size
    char label[64] = {};
    ImU32 color = 0x44888888;     // fill color (translucent)
    bool selected = false;        // multi-select flag
};

static std::vector<VsNode> sVsNodes;
static std::vector<VsLink> sVsLinks;
static std::vector<VsAnnotation> sVsAnnotations;
static int sVsNextId = 1;
static int sVsSelected = -1;     // selected node index (-1 = none)
static float sVsPanX = 0, sVsPanY = 0;   // canvas pan offset
static float sVsZoom = 1.0f;
// Dragging state
static bool sVsDraggingNode = false;
static bool sVsDraggingCanvas = false;
static bool sVsDraggingLink = false;
static VsPin sVsLinkStart = {};
static ImVec2 sVsLinkEndPos = {};
// Box selection
static bool sVsBoxSelecting = false;
static ImVec2 sVsBoxStart = {};        // screen-space start of selection box
// Group navigation
static int sVsEditingGroup = 0;        // 0 = top-level; >0 = inside group node id
static float sVsParentPanX = 0, sVsParentPanY = 0;
static float sVsParentZoom = 1.0f;
// Group pin mappings: which internal pin maps to which group-node pin
struct VsGroupPinMap {
    int groupNodeId;
    int pinType, pinIdx;           // pin on the group node
    int innerNodeId;
    int innerPinType, innerPinIdx; // pin on the internal node
};
static std::vector<VsGroupPinMap> sVsGroupPins;

// ---- Blueprint Script Asset System ----
// Parameter slot exposed by a blueprint for per-instance override
struct BpParam {
    char name[32] = {};          // display name ("Patrol Speed")
    int  sourceNodeId = -1;      // which VsNode provides the default
    int  sourceParamIdx = 0;     // which paramInt[] slot (0-3)
    int  dataType = 0;           // 0=int, 1=float, 2=key, 3=direction, 4=animation
    int  defaultInt = 0;         // default value
};

struct BlueprintAsset {
    char name[32] = "Script";
    std::vector<VsNode>        nodes;
    std::vector<VsLink>        links;
    std::vector<VsAnnotation>  annotations;
    std::vector<VsGroupPinMap> groupPins;
    int nextId = 1;
    float panX = 0, panY = 0, zoom = 1.0f;
    BpParam params[8] = {};
    int paramCount = 0;
};

static std::vector<BlueprintAsset> sBlueprintAssets;
static int sSelectedBlueprint = -1;

// Track what the node editor is currently editing
enum class VsEditSource { Scene, Blueprint };
static VsEditSource sVsEditSource = VsEditSource::Scene;
static int sVsEditBlueprintIdx = -1;

// Per-instance override (on objects that reference blueprints)
struct BpInstanceParam {
    int paramIdx = 0;   // index into BlueprintAsset::params[]
    int value = 0;      // overridden value
};

// ---- Sound / Sample Bank ----

struct DrumHit {
    std::vector<int8_t> data;
    int sampleRate = 16384;
    char name[32] = "";
};

struct SampleRegion {
    std::vector<int8_t> data;
    std::vector<int16_t> data16; // 16-bit for SF2 (editor preview only)
    int sampleRate = 16384;
    int baseNote = 60;
    int keyLo = 0, keyHi = 127;
    bool hasLoop = false;
    int loopStart = 0;
    int loopEnd = 0;
    int peakAmplitude = 32768; // peak amplitude for normalization (16-bit scale)
    int fineTune = 0;     // fine tuning in cents (-100 to +100)
    // SF2 volume envelope (timecents, -12000 = 1ms, 0 = 1s, 1200 = 2s)
    float envDecaySec = 0;    // decay time in seconds (0 = not set)
    float envSustainDb = 0;   // sustain attenuation in dB (0 = full, 100 = silent)
    float envReleaseSec = 0;  // release time in seconds
};

struct EnvPoint {
    float time = 0;   // 0.0-1.0 normalized position
    float level = 1;  // 0.0-1.0 amplitude
    bool operator==(const EnvPoint& o) const { return time == o.time && level == o.level; }
    bool operator!=(const EnvPoint& o) const { return !(*this == o); }
};

enum SampleCategory { SmpCat_Oscillator = 0, SmpCat_Noise = 1, SmpCat_GM = 2, SmpCat_Import = 3, SmpCat_SF2 = 4 };

struct SoundSample {
    char name[32] = "Sample";
    std::vector<int8_t> data;   // 8-bit signed PCM (downsampled for MIDI instruments)
    std::vector<int16_t> srcData16; // original 16-bit data at srcRate (for SFX export)
    int sampleRate = 16384;     // Hz (for MIDI instrument playback)
    int srcRate = 0;            // original WAV sample rate (0 = no hi-res data)
    bool loop = false;
    int loopStart = 0;          // sample offset (actual position, not percentage)
    int loopEnd = 0;            // sample offset (0 = end of sample)
    bool loopFromDLS = false;   // true = initialized from DLS, skip crossfade
    bool noSustainLoop = false; // true = ignore DLS sustain loops (percussive instruments)
    bool builtIn = false;       // true = generated, not imported
    bool isDrumKit = false;     // true = note selects sample from drumHits
    int category = SmpCat_Oscillator; // UI grouping category
    DrumHit drumHits[128];      // per-note samples (only used if isDrumKit)
    // Envelope shaper (editable amplitude curve)
    std::vector<EnvPoint> envelope; // if empty, no envelope applied
    bool envEnabled = false;
    float ampGainDb = 0.0f;        // amplify gain in dB (imported samples only)
    int octaveShift = 0;           // pitch shift in octaves (-3 to +3)
    int baseNote = 60;             // MIDI note the sample was recorded at (for pitch calc)
    int releaseMs = 250;           // release fade-out time in ms (0 = no fade)
    int decayPct = 0;              // volume decay over note duration (0-100%, 0 = no decay)
    int decayMinMs = 500;          // minimum note length for decay to apply (ms)
    std::vector<SampleRegion> regions; // multi-sample regions (GM instruments)
    // DLS articulation LFO vibrato
    float lfoFreqHz = 5.0f;       // vibrato LFO rate in Hz
    float lfoDepthCents = 0.0f;   // default vibrato depth in cents (always active)
    float lfoCC1Cents = 0.0f;     // vibrato depth in cents at CC#1=127
    bool vibratoEnabled = true;   // toggle for LFO/modulation vibrato
};

struct MidiNote {
    int tick;           // absolute tick position
    int channel;        // MIDI channel 0-15
    int note;           // MIDI note number 0-127
    int velocity;       // 0-127
    int duration;       // length in ticks
};

struct MidiPitchBend {
    int tick;
    int channel;
    int value; // -8192 to +8191 (0 = center)
};

struct MidiCC {
    int tick;
    int channel;
    int cc;     // controller number (1 = modulation, etc.)
    int value;  // 0-127
};

struct MidiTrack {
    char name[32] = "Track";
    std::vector<MidiNote> notes;
    std::vector<MidiPitchBend> bends;
    std::vector<MidiCC> ccs;
};

