// Per-sample overrides (waveform edits + envelope) stored per-instance
struct SampleOverride {
    int sampleIdx = -1;
    std::vector<int8_t> data;       // edited PCM (empty = no waveform override)
    std::vector<EnvPoint> envelope; // edited envelope (empty = no env override)
    bool envEnabled = false;
    int octaveShift = 0;            // pitch shift in octaves
    bool hasOctave = false;         // true if octave was overridden
    int releaseMs = -1;             // -1 = not overridden
    int decayPct = -1;
    int decayMinMs = -1;
};

// Sound instances — named slots referencing a MIDI + bank config for export
struct SoundInstance {
    char name[48] = "Untitled";
    int midiIdx = -1;           // index into sMidiFiles (-1 = none)
    int sfxSampleIdx = -1;      // index into sSoundBank (-1 = MIDI mode, >=0 = SFX one-shot)
    int channelBank[16] = {};   // per-channel sample bank override
    int volume = 100;           // master volume 0-100
    int interpolation = 0;     // 0 = nearest, 1 = smooth (linear)
    int mixerGain = 0;         // 0=Normal(>>7), 1=Loud(>>6), 2=Mid(>>8), 3=Quiet(>>9), 4=Louder(>>5), 5=Loudest(>>4)
    int fifoChannel = 0;       // 0 = FIFO A, 1 = FIFO B
    int voiceCount = 6;        // max simultaneous voices on GBA (4-8)
    int softFade = 1;          // 0 = hard cutoff, 1 = 256-sample fadeout at end of notes
    int longRelease = 0;       // 0 = normal, 1 = force minimum 1672-sample (~67ms) release tail
    int hifiMode = 0;          // 0 = normal (~18kHz), 1 = hi-fi (~25kHz, may trill)
    int compatMode = 0;        // 0 = normal, 1 = compatibility (halved rate, no interp, no release — less CPU)
    int bufferScale = 0;       // 0 = normal (1 VBlank), 1 = scale buffer to match frame time (for low FPS)
    bool loop = false;          // loop playback between loopStart and loopEnd ticks
    int loopStartTick = 0;      // loop region start (MIDI ticks)
    int loopEndTick = 0;        // loop region end (MIDI ticks, 0 = end of sequence)
    std::vector<SampleOverride> overrides; // per-sample edits
};
