    // General
    bool visible = true;
    int layer = 0;           // draw order (higher = on top)
    int blueprintIdx = -1;   // blueprint instance (-1 = none)
    int runtimeMode = 0;     // 0=Both, 1=Mode 4 Only, 2=Mode 0 Only
