                if (ms.spriteCount > 0) {
                    int cnt = 0; sscanf(line + 17, "%d", &cnt);
                    ms.sprites[ms.spriteCount - 1].subSpriteCount = std::min(cnt, (int)FloorSprite::kMaxSubSprites);
                }
