                        case VsNodeType::SetFriction:   return "_set_friction";
                        case VsNodeType::CloneSprite:   return "_clone";
                        case VsNodeType::HideAll:       return "_hide_all";
                        case VsNodeType::ShowAll:       return "_show_all";
