                case VsNodeType::DialogueChoice:
                    editorCode = "// Branch on player choice";
                    setActionFunc(infoNode, "_dlg_choice",
                        "    afn_dlg_choice_a = choiceA;\n"
                        "    afn_dlg_choice_b = choiceB;\n"
                        "    afn_dlg_choosing = 1;\n"
                        "    // branches to A or B output");
