                        if (si.spriteAssetIdx >= 0 && si.spriteAssetIdx < (int)sSpriteAssets.size()) {
                            int maxFr = std::max(0, (int)sSpriteAssets[si.spriteAssetIdx].frames.size() - 1);
                            if (ImGui::SliderInt("Frame##spr", &si.frame, 0, maxFr)) sProjectDirty = true;
                        }
